-- 9. Create Suppliers Table

CREATE TABLE IF NOT EXISTS suppliers (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  name TEXT NOT NULL,
  phone TEXT,
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE TABLE IF NOT EXISTS inventory_items (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  name TEXT NOT NULL,
  unit TEXT NOT NULL,
  stock_main NUMERIC DEFAULT 0,
  stock_factory NUMERIC DEFAULT 0,
  stock_distribution NUMERIC DEFAULT 0,
  last_purchase_price NUMERIC DEFAULT 0,
  avg_purchase_price NUMERIC DEFAULT 0,
  units_per_carton INTEGER DEFAULT 1,
  units_per_box INTEGER DEFAULT 1,
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE TABLE IF NOT EXISTS purchase_invoices (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  supplier_id UUID REFERENCES suppliers(id) ON DELETE SET NULL,
  supplier_name TEXT,
  invoice_date TIMESTAMPTZ DEFAULT now(),
  items JSONB NOT NULL,
  total_amount NUMERIC NOT NULL,
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE TABLE IF NOT EXISTS manufacturing_orders (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  status TEXT DEFAULT 'pending',
  items JSONB NOT NULL,
  requested_by TEXT NOT NULL,
  approved_by TEXT,
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE TABLE IF NOT EXISTS production_logs (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  produced_items JSONB NOT NULL,
  consumed_items JSONB NOT NULL,
  recorded_by TEXT NOT NULL,
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE TABLE IF NOT EXISTS product_recipes (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  product_id UUID REFERENCES products(id) ON DELETE CASCADE,
  inventory_item_id UUID REFERENCES inventory_items(id) ON DELETE CASCADE,
  quantity NUMERIC NOT NULL,
  created_at TIMESTAMPTZ DEFAULT now(),
  UNIQUE(product_id, inventory_item_id)
);

ALTER TABLE orders ADD COLUMN IF NOT EXISTS inventory_deducted BOOLEAN DEFAULT false;

-- Enable RLS
ALTER TABLE suppliers ENABLE ROW LEVEL SECURITY;
ALTER TABLE inventory_items ENABLE ROW LEVEL SECURITY;
ALTER TABLE purchase_invoices ENABLE ROW LEVEL SECURITY;
ALTER TABLE manufacturing_orders ENABLE ROW LEVEL SECURITY;
ALTER TABLE production_logs ENABLE ROW LEVEL SECURITY;
ALTER TABLE product_recipes ENABLE ROW LEVEL SECURITY;

-- Permissive Policies
DROP POLICY IF EXISTS "Allow all for everyone" ON suppliers;
CREATE POLICY "Allow all for everyone" ON suppliers FOR ALL USING (true) WITH CHECK (true);

DROP POLICY IF EXISTS "Allow all for everyone" ON inventory_items;
CREATE POLICY "Allow all for everyone" ON inventory_items FOR ALL USING (true) WITH CHECK (true);

DROP POLICY IF EXISTS "Allow all for everyone" ON purchase_invoices;
CREATE POLICY "Allow all for everyone" ON purchase_invoices FOR ALL USING (true) WITH CHECK (true);

DROP POLICY IF EXISTS "Allow all for everyone" ON manufacturing_orders;
CREATE POLICY "Allow all for everyone" ON manufacturing_orders FOR ALL USING (true) WITH CHECK (true);

DROP POLICY IF EXISTS "Allow all for everyone" ON production_logs;
CREATE POLICY "Allow all for everyone" ON production_logs FOR ALL USING (true) WITH CHECK (true);

DROP POLICY IF EXISTS "Allow all for everyone" ON product_recipes;
CREATE POLICY "Allow all for everyone" ON product_recipes FOR ALL USING (true) WITH CHECK (true);


